const input = $input.first().json;
const text = (input.message?.text || input.text || '').trim();

if (!text.toLowerCase().startsWith('#debrief')) {
  return [];
}

const cleaned = text.replace(/^#debrief\s*/i, '').trim();
if (!cleaned) {
  return [];
}

return [{
  json: {
    ...input,
    text: cleaned
  }
}];

const text = $input.first().json.text;
const apiKey = 'PASTE_NEW_CLAUDE_KEY_HERE';
const today = new Date().toISOString().slice(0, 10);

if (!apiKey || apiKey.includes('PASTE_')) {
  throw new Error('Claude API key is missing in Parse with Claude node.');
}

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.anthropic.com/v1/messages',
    headers: {
      'x-api-key': apiKey,
      'anthropic-version': '2023-06-01',
      'content-type': 'application/json'
    },
    json: true,
    body: {
      model: 'claude-3-5-sonnet-20241022',
      max_tokens: 500,
      temperature: 0.2,
      messages: [
        {
          role: 'user',
          content: `Parse this Debrief into JSON with exactly these fields:\n- date (YYYY-MM-DD, use ${today} if not specified)\n- technique (main technique as string)\n- keyPoints (array of 2-3 key points as strings)\n- reflections (personal insights as string)\n\nReturn ONLY valid JSON, no markdown.\n\nNote: ${text}`
        }
      ]
    }
  });

  const raw = response?.content?.[0]?.text ?? '{}';
  const cleaned = raw
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();

  const parsed = JSON.parse(cleaned);

  return [{
    json: {
      Date: parsed.date || today,
      Technique: parsed.technique || '',
      'Key Points': Array.isArray(parsed.keyPoints) ? parsed.keyPoints.join(' | ') : (parsed.keyPoints || ''),
      Reflections: parsed.reflections || '',
      'Raw Notes': text
    }
  }];
} catch (err) {
  const details = err?.response?.body ? JSON.stringify(err.response.body) : err.message;
  throw new Error(`Claude request failed: ${details}`);
}
